import Router from './components/routes';
import LanguageProvider from './context/language';
import ToneModeProvider from './context/nightmode';

function App() {
	return (
		<div className="bg-slate-900 h-100">
			<ToneModeProvider>
				<LanguageProvider>
					<Router />
				</LanguageProvider>
			</ToneModeProvider>
		</div>
	);
}

export default App;
